#nullable enable // autogenerated

using System;
using System.Collections;
using System.Collections.Generic;
using System.Linq;
using MVZ2.Metas;
using MVZ2.Modding;
using MVZ2.Sprites;
using MVZ2.Talk;
using MVZ2.TalkData;
using MVZ2.UI.Talk;
using MVZ2Logic.Localization;
using PVZEngine;
using UnityEngine;

namespace MVZ2.Managers
{
    public partial class ResourceManager : MonoBehaviour
    {
        #region 元数据列表
        public TalkCharacterMetaList? GetCharacterMetaList(string nsp)
        {
            var modResource = main.ResourceManager.GetModResource(nsp);
            if (modResource == null)
                return null;
            return modResource.TalkCharacterMetaList;
        }
        #endregion

        #region 元数据
        public TalkCharacterMeta? GetCharacterMeta(NamespaceID? characterID)
        {
            if (!NamespaceID.IsValid(characterID))
                return null;
            var modResource = main.ResourceManager.GetModResource(characterID.SpaceName);
            if (modResource?.TalkCharacterMetaList == null)
                return null;
            return modResource.TalkCharacterMetaList.metas.FirstOrDefault(m => m.id == characterID.Path);
        }
        #endregion

        public string GetCharacterName(NamespaceID? characterID)
        {
            var character = GetCharacterMeta(characterID);
            return GetCharacterName(character?.name ?? string.Empty);
        }
        public string GetCharacterName(string nameKey)
        {
            return main.LanguageManager._p(LogicStrings.CONTEXT_CHARACTER_NAME, nameKey);
        }


        private void LoadUnlocks_Characters(ModResource resource)
        {
            if (resource.TalkCharacterMetaList == null)
                return;
            foreach (var meta in resource.TalkCharacterMetaList.metas)
            {
                foreach (var variant in meta.variants)
                {
                    AddConditionListUnlocks(variant.unlock);
                }
            }
        }
    }
}
